import * as XLSX from 'xlsx';
import Anthropic from '@anthropic-ai/sdk';

interface ExcelParseResult {
  sheets: Array<{
    name: string;
    rowCount: number;
    columnCount: number;
    headers: string[];
    sample: Record<string, any>[]; // First 5 rows
    dataTypes: Record<string, string>; // Inferred types per column
  }>;
  summary: string;
  suggestedMappings: Array<{
    sheetName: string;
    dataType: 'transactions' | 'team_members' | 'documents' | 'obligations';
    confidence: number;
    columnMappings: Record<string, string>;
  }>;
}

export async function parseExcelFile(
  buffer: Buffer,
  fileName: string
): Promise<ExcelParseResult> {
  // Use xlsx package (^0.18.5) - most popular, well-maintained
  const workbook = XLSX.read(buffer, { type: 'buffer' });

  const sheets = workbook.SheetNames.map((sheetName) => {
    const worksheet = workbook.Sheets[sheetName];
    const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 });

    // Extract headers and infer column types
    const headers = jsonData[0] as string[];
    const dataRows = jsonData.slice(1);
    const sample = dataRows.slice(0, 5).map((row: any[]) => 
      headers.reduce((obj, header, i) => ({ ...obj, [header]: row[i] }), {})
    );

    // Infer data types
    const dataTypes = inferColumnTypes(dataRows, headers);

    return {
      name: sheetName,
      rowCount: dataRows.length,
      columnCount: headers.length,
      headers,
      sample,
      dataTypes,
    };
  });

  // Use Claude to understand the Excel structure
  const anthropic = new Anthropic();
  const analysisPrompt = `Analyze this Excel file structure and suggest data mappings:

${JSON.stringify(sheets, null, 2)}

Suggest which sheets map to: transactions, team_members, documents, or obligations.
For each, provide column mappings to our schema and confidence score (0-1).
Return JSON array of suggestions.`;

  const response = await anthropic.messages.create({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2048,
    messages: [{ role: 'user', content: analysisPrompt }],
  });

  const aiSuggestions = parseAIResponse(response);

  return {
    sheets,
    summary: generateSummary(sheets),
    suggestedMappings: aiSuggestions,
  };
}

