import type { Business, Transaction, TeamMember, Document, Obligation } from '@/lib/supabase/types';

interface BusinessContext {
  business: Business;
  recentTransactions: Transaction[];
  upcomingObligations: Obligation[];
  documentStatus: Array<{ type: string; expiringSoon: boolean; expiryDate: string | null }>;
  teamSummary: {
    totalEmployees: number;
    saudiEmployees: number;
    saudizationRatio: number;
    totalMonthlySalary: number;
