export async function buildContextForQuery(
  businessId: string,
  userQuery: string
): Promise<string> {
  const supabase = await createClient();

  // Use keyword matching to determine relevant data
  const needsFinancials = /spend|expense|revenue|income|vat|transaction|payment|cost/i.test(userQuery);
  const needsCompliance = /expire|due|obligation|compliance|gosi|zatca|cr|certificate/i.test(userQuery);
  const needsTeam = /employee|team|salary|saudization|staff|hire/i.test(userQuery);

  const context: Partial<BusinessContext> = {
    business: await getBusinessInfo(supabase, businessId),
  };

  if (needsFinancials) {
    context.recentTransactions = await getRecentTransactions(supabase, businessId, 30);
  }

  if (needsCompliance) {
    context.upcomingObligations = await getUpcomingObligations(supabase, businessId, 90);
    context.documentStatus = await getDocumentStatus(supabase, businessId);
    context.complianceAlerts = await generateComplianceAlerts(supabase, businessId);
  }

  if (needsTeam) {
    context.teamSummary = await getTeamSummary(supabase, businessId);
  }

  // Format context as structured prompt
  return formatContextPrompt(context);
}

