```typescript
import Anthropic from '@anthropic-ai/sdk';
import { createClient } from '@/lib/supabase/server';
import { buildContextForQuery } from '@/lib/chat/context-builder';
import { claudeTools, executeAction } from '@/lib/chat/actions';
import { checkRateLimit } from '@/lib/rate-limit';

const CLAUDE_MODEL = 'claude-sonnet-4-20250514';

interface ChatRequest {
  conversationId?: string; // If continuing conversation
  message: string;
  businessId: string;
  fileUploads?: Array<{ id: string; type: string; url: string }>;
}

export async function POST(request: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    return new Response('Unauthorized', { status: 401 });
  }

  const body: ChatRequest = await request.json();

  // Rate limiting
  const rateCheck = await checkRateLimit(body.businessId);
  if (!rateCheck.allowed) {
    return Response.json({ error: 'Rate limit exceeded' }, { status: 429 });
  }

  // Get or create conversation
  let conversationId = body.conversationId;
  if (!conversationId) {
    const { data: conv } = await supabase
      .from('conversations')
      .insert({ business_id: body.businessId })
      .select('id')
      .single();
    conversationId = conv!.id;
  }

  // Store user message
  await supabase.from('chat_messages').insert({
    conversation_id: conversationId,
    role: 'user',
    content: body.message,
    message_type: 'text',
  });

  // Build context
  const contextPrompt = await buildContextForQuery(body.businessId, body.message);

  // Load conversation history (last 20 messages)
  const { data: history } = await supabase
    .from('chat_messages')
    .select('role, content')
    .eq('conversation_id', conversationId)
    .order('created_at', { ascending: true })
    .limit(20);

  const anthropic = new Anthropic();

  // System prompt
  const systemPrompt = `You are Mugdm AI, the CEO's virtual COO for Saudi Arabian businesses.

You help with:
- Analyzing financial data and providing insights
- Managing compliance obligations (GOSI, ZATCA, CR renewals)
- Tracking team members and Saudization
- Processing Excel files and importing data
- Taking actions via tools when requested

Always respond in the user's language (Arabic or English).
Be proactive with suggestions and warnings.
Use Saudi Arabian context (SAR currency, Hijri dates, local regulations).

${contextPrompt}`;

  // Stream response
  const stream = await anthropic.messages.create({
    model: CLAUDE_MODEL,
    max_tokens: 4096,
    system: systemPrompt,
    messages: [
      ...history.map(h => ({ role: h.role, content: h.content })),
      { role: 'user', content: body.message },
    ],
    tools: claudeTools,
    stream: true,
  });

  // Create readable stream for client
  const encoder = new TextEncoder();
  const readable = new ReadableStream({
    async start(controller) {
      let fullResponse = '';
      let toolUseRequests: any[] = [];

      for await (const event of stream) {
        if (event.type === 'content_block_delta') {
          if (event.delta.type === 'text_delta') {
            fullResponse += event.delta.text;
            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'text', content: event.delta.text })}\n\n`));
          }
        }

        if (event.type === 'content_block_start' && event.content_block.type === 'tool_use') {
          // Claude is requesting to use a tool
          toolUseRequests.push(event.content_block);
          controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'tool_use_request', tool: event.content_block })}\n\n`));
        }

        if (event.type === 'message_stop') {
          // Store assistant response
          await supabase.from('chat_messages').insert({
            conversation_id: conversationId,
            role: 'assistant',
            content: fullResponse,
            message_type: toolUseRequests.length > 0 ? 'action_confirmation' : 'text',
            metadata: toolUseRequests.length > 0 ? { tool_use: toolUseRequests } : null,
          });

          controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'done', conversationId })}\n\n`));
          controller.close();
        }
      }
    },
  });

  return new Response(readable, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    },
  });
}
