export async function importExcelData(
  businessId: string,
  fileId: string,
  mappings: ImportMapping[],
  options: ImportOptions
): Promise<ImportResult> {
  const supabase = await createClient();

  // Fetch parsed Excel data
  const { data: file } = await supabase
    .from('chat_file_uploads')
    .select('processing_result')
    .eq('id', fileId)
    .single();

  const excelData = file!.processing_result;
  const results: ImportResult = {
    imported: 0,
    skipped: 0,
    errors: [],
  };

  for (const mapping of mappings) {
    const sheet = excelData.sheets.find(s => s.name === mapping.sheetName);
    if (!sheet) continue;

    switch (mapping.dataType) {
      case 'transactions':
        const txResult = await importTransactions(
          supabase,
          businessId,
          sheet.data,
          mapping.columnMappings,
          options.skipDuplicates
        );
        results.imported += txResult.imported;
        results.skipped += txResult.skipped;
        results.errors.push(...txResult.errors);
        break;

      case 'team_members':
        // Similar logic...
        break;

      // Handle other data types...
    }
  }

  return results;
}

async function importTransactions(
  supabase: SupabaseClient,
  businessId: string,
  rows: any[],
  columnMappings: Record<string, string>,
  skipDuplicates: boolean
): Promise<{ imported: number; skipped: number; errors: string[] }> {
  const errors: string[] = [];
  let imported = 0;
  let skipped = 0;

  for (const [index, row] of rows.entries()) {
    try {
      // Map columns to transaction schema
      const transaction = {
        business_id: businessId,
        date: parseDate(row[columnMappings.date]),
        amount: parseFloat(row[columnMappings.amount]),
        type: row[columnMappings.type] || 'EXPENSE',
        category: mapCategory(row[columnMappings.category]),
        description: row[columnMappings.description],
        vendor_or_client: row[columnMappings.vendor],
        source: 'MANUAL' as const,
        vat_amount: row[columnMappings.vat] ? parseFloat(row[columnMappings.vat]) : null,
        is_reviewed: true,
      };

      // Check for duplicates
      if (skipDuplicates) {
        const { data: existing } = await supabase
          .from('transactions')
          .select('id')
          .eq('business_id', businessId)
          .eq('date', transaction.date)
          .eq('amount', transaction.amount)
          .eq('vendor_or_client', transaction.vendor_or_client)
          .maybeSingle();

        if (existing) {
          skipped++;
          continue;
        }
      }

      // Insert transaction
      const { error } = await supabase
        .from('transactions')
        .insert(transaction);

      if (error) throw error;
      imported++;
    } catch (err) {
      errors.push(`Row ${index + 1}: ${err.message}`);
    }
  }

  return { imported, skipped, errors };
}
```

